  ('dietitian-moex-11202', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列關於化學反應自由能變化（ΔG）的敘述，何者不正確？ 會隨著反應物的濃度而變化  在反應達平衡時，其值為0 其值與反應速率無關     其值為常數', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
